external_knowledge:
- 'storm-tamer hurlers' refers to pitchers;
- 'fanned over a dozen flames' refers to pitchers having more than 10 wins;
- 'turbulent defensive waters' refers to ERA (Earned Run Average);
- 'from the most tumultuous to the calmest' means ordering pitchers by their average ERA in descending order.

sql:
SELECT COUNT(DISTINCT player_id)
FROM awards
WHERE season_id = (SELECT season_id FROM seasons WHERE season_name = '2022 Season');

SELECT AVG(total_games_played) AS avg_games_played
FROM (
    SELECT player_id, SUM(gp) AS total_games_played
    FROM player_game_stats
    GROUP BY player_id
) AS PlayerGameStats;
